CREATE TABLE employees (
  id     INTEGER PRIMARY KEY,
  name   TEXT,
  dept   TEXT,
  salary INTEGER
);
INSERT INTO employees VALUES (1, 'Alice', 'Engineering', 95000);
INSERT INTO employees VALUES (2, 'Bob',   'Marketing',   72000);
INSERT INTO employees VALUES (3, 'Carol', 'Engineering', 105000);
INSERT INTO employees VALUES (4, 'Dave',  'HR',          68000);

SELECT name, salary FROM employees WHERE dept = 'Engineering';

CREATE TABLE products (id INTEGER, name TEXT, price REAL, in_stock INTEGER);
INSERT INTO products VALUES (1, 'Laptop', 999.99, 1);
INSERT INTO products VALUES (2, 'Mouse',  29.99,  1);
INSERT INTO products VALUES (3, 'Monitor', 399.99, 0);
INSERT INTO products VALUES (4, 'Keyboard', 79.99, 1);

SELECT name, price FROM products
WHERE in_stock = 1 AND price < 100;

CREATE TABLE users (id INTEGER, name TEXT, email TEXT);
INSERT INTO users VALUES (1, 'Alice Smith', 'alice@gmail.com');
INSERT INTO users VALUES (2, 'Bob Jones',   'bob@yahoo.com');
INSERT INTO users VALUES (3, 'Carol Brown', 'carol@gmail.com');
INSERT INTO users VALUES (4, 'Dave Wilson', 'dave@company.com');

SELECT name FROM users WHERE email LIKE '%@gmail.com';

CREATE TABLE orders (id INTEGER, customer TEXT, total REAL, status TEXT);
INSERT INTO orders VALUES (1, 'Alice', 45.99, 'delivered');
INSERT INTO orders VALUES (2, 'Bob',   120.00, 'shipped');
INSERT INTO orders VALUES (3, 'Carol', 89.50, 'cancelled');
INSERT INTO orders VALUES (4, 'Dave',  15.99, 'delivered');
INSERT INTO orders VALUES (5, 'Eve',   200.00, 'shipped');

SELECT customer, total FROM orders
WHERE status IN ('delivered', 'shipped')
  AND total BETWEEN 40 AND 150;
